const raw = $input.first().json;
let msg;
try {
  const payload = raw.message || raw.body || raw;
  msg = typeof payload === 'string' ? JSON.parse(payload) : payload;
} catch(e) {
  throw new Error('Malformed MQTT message: cannot parse JSON payload. ' + e.message);
}

if (!msg.action || !msg.file_hash || !msg.file_path) {
  throw new Error('Invalid lifecycle message: missing required fields (action, file_hash, file_path). Got keys: ' + JSON.stringify(Object.keys(msg)));
}

if (!['add_path', 'update_path'].includes(msg.action)) {
  console.warn('[alice-dms-lifecycle] Unknown action: ' + msg.action + ' — discarding message');
  return [];
}

return [{ json: { ...msg } }];

const axios = require('axios');
const item = $input.first().json;
const rawHash = item.file_hash;

// BUG-4 fix: sanitize file_hash to prevent GraphQL injection
const fileHash = String(rawHash).replace(/[^a-zA-Z0-9:]/g, '');
if (fileHash !== rawHash) {
  console.warn(`[alice-dms-lifecycle] Sanitized file_hash: '${rawHash}' -> '${fileHash}'`);
}
if (!fileHash) {
  throw new Error('file_hash is empty after sanitization, cannot query Weaviate');
}

const WEAVIATE = 'http://weaviate:8080';
const collections = ['Invoice', 'BankStatement', 'Document', 'Email', 'SecuritySettlement', 'Contract'];

let foundClass = null;
let foundId = null;
let foundAdditionalPaths = [];

for (const cls of collections) {
  const q = `{ Get { ${cls}(where: { path: ["fileHash"], operator: Equal, valueText: "${fileHash}" }, limit: 1) { _additional { id } additionalPaths } } }`;
  try {
    const r = await axios.post(`${WEAVIATE}/v1/graphql`, { query: q }, {
      headers: { 'Content-Type': 'application/json' },
      timeout: 10000
    });
    const hits = r.data?.data?.Get?.[cls];
    if (hits && hits.length > 0) {
      foundClass = cls;
      foundId = hits[0]._additional?.id;
      foundAdditionalPaths = hits[0].additionalPaths || [];
      break;
    }
  } catch(e) {
    // continue to next collection
  }
}

if (!foundId) {
  console.warn(`[alice-dms-lifecycle] Object not found in Weaviate for hash: ${fileHash}`);
}

return [{ json: { ...item, _weaviate_class: foundClass, _weaviate_id: foundId, _existing_additional_paths: foundAdditionalPaths } }];

const axios = require('axios');
const item = $input.first().json;
const WEAVIATE = 'http://weaviate:8080';

if (!item._weaviate_id || !item._weaviate_class) {
  console.warn(`[alice-dms-lifecycle] add_path: no Weaviate object found for hash ${item.file_hash}, skipping PATCH`);
  return [{ json: { ...item, _weaviate_patched: false } }];
}

const existing = Array.isArray(item._existing_additional_paths) ? item._existing_additional_paths : [];
const newPaths = [...new Set([...existing, item.file_path])];

try {
  await axios.patch(
    `${WEAVIATE}/v1/objects/${item._weaviate_class}/${item._weaviate_id}`,
    { properties: { additionalPaths: newPaths } },
    { headers: { 'Content-Type': 'application/json' }, timeout: 10000 }
  );
} catch(e) {
  throw new Error(`Weaviate PATCH failed for add_path (${item.file_hash}): ${e.message}`);
}

return [{ json: { ...item, _weaviate_patched: true, _new_additional_paths: newPaths } }];

const redis = require('redis');
const item = $input.first().json;
let redisPw = ''; try { redisPw = $env.REDIS_PASSWORD || ''; } catch(e) {}
const client = redis.createClient({ socket: { host: 'redis', port: 6379 }, password: redisPw || undefined });
await client.connect();
try {
  await client.hSet('alice:dms:path_to_hash', item.file_path, item.file_hash);
  await client.sAdd(`alice:dms:hash_to_paths:${item.file_hash}`, item.file_path);
} finally {
  await client.quit();
}
return [{ json: { ...item, _redis_updated: true } }];

const axios = require('axios');
const item = $input.first().json;
const WEAVIATE = 'http://weaviate:8080';

if (!item._weaviate_id || !item._weaviate_class) {
  console.warn(`[alice-dms-lifecycle] update_path: no Weaviate object found for hash ${item.file_hash}, skipping PATCH`);
  return [{ json: { ...item, _weaviate_patched: false } }];
}

try {
  await axios.patch(
    `${WEAVIATE}/v1/objects/${item._weaviate_class}/${item._weaviate_id}`,
    { properties: { filePath: item.file_path } },
    { headers: { 'Content-Type': 'application/json' }, timeout: 10000 }
  );
} catch(e) {
  throw new Error(`Weaviate PATCH failed for update_path (${item.file_hash}): ${e.message}`);
}

return [{ json: { ...item, _weaviate_patched: true } }];

const redis = require('redis');
const item = $input.first().json;
const oldPaths = Array.isArray(item.old_paths) ? item.old_paths : [];
let redisPw = ''; try { redisPw = $env.REDIS_PASSWORD || ''; } catch(e) {}
const client = redis.createClient({ socket: { host: 'redis', port: 6379 }, password: redisPw || undefined });
await client.connect();
try {
  for (const op of oldPaths) {
    await client.hDel('alice:dms:path_to_hash', op);
    await client.sRem(`alice:dms:hash_to_paths:${item.file_hash}`, op);
  }
  await client.hSet('alice:dms:path_to_hash', item.file_path, item.file_hash);
  await client.sAdd(`alice:dms:hash_to_paths:${item.file_hash}`, item.file_path);
} finally {
  await client.quit();
}
return [{ json: { ...item, _redis_updated: true } }];

const errorData = $input.first().json;
const errorMsg = {
  workflow: 'alice-dms-lifecycle',
  error: errorData.execution?.error?.message || 'Unknown error',
  node: errorData.execution?.lastNodeExecuted || 'unknown',
  timestamp: new Date().toISOString(),
  execution_id: errorData.execution?.id || null
};
return [{ json: errorMsg }];
